mapper.select:
SELECT  
  FROM  TB_CTSNN_MANAGE A
 WHERE  A.CTSNN_ID = #{ctsnnId}

mapper.insert:
INSERT  INTO TB_CTSNN_MANAGE
      ( CTSNN_ID
      , USER_ID
      , CTSNN_CODE
      , REQST_DE
      , CTSNN_NM
      , TRGTER_NM
      , BRTHDY
      , OCCRRNC_DE
      , RELATE
      , RM
      , SANCTNER_ID
      , CONFM_AT
      , INFRML_SANCTN_ID
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{ctsnnId}
        , #{usid}
        , #{ctsnnCd}
        , #{reqstDe}
        , #{ctsnnNm}
        , #{trgterNm}
        , #{brth}
        , #{occrrDe}
        , #{relate}
        , #{remark}
        , #{sanctnerId}
        , #{confmAt}
        , #{infrmlSanctnId}
        , #{frstRegisterId}
        , CURRENT_TIMESTAMP )

mapper.update:
UPDATE  TB_CTSNN_MANAGE
   SET  CTSNN_CODE      = #{ctsnnCd}
      , REQST_DE        = #{reqstDe}
      , CTSNN_NM        = #{ctsnnNm}
      , TRGTER_NM       = #{trgterNm}
      , BRTHDY          = #{brth}
      , OCCRRNC_DE      = #{occrrDe}
      , RELATE          = #{relate}
      , RM              = #{remark}
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  CTSNN_ID = #{ctsnnId}

UPDATE  TB_CTSNN_MANAGE
   SET  CONFM_AT        = #{confmAt}
      , SANCTN_DT       = #{sanctnDt}
      , RETURN_RESN     = #{returnResn}
      , SANCTNER_ID     = #{sanctnerId}
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  CTSNN_ID = #{ctsnnId}
